INSERT INTO games (title, description, author, folder_name, category, age_group, approved) VALUES ('Memoria ASCII', 'Juego de memoria donde emparejas letras con sus códigos ASCII.', 'Agustin Muñoz', 'ascii-memory', 'Códigos de caracteres', '9-12 años', 1);
INSERT INTO games (title, description, author, folder_name, category, age_group, approved) VALUES ('Código Perdido', 'Juego narrativo que combina una historia de recuperación de memoria con desafíos para aprender Python.', 'Sofia Rodriguez', 'codigo-perdido', 'Python', '9-12 años', 1);
INSERT INTO games (title, description, author, folder_name, category, age_group, approved) VALUES ('Juego del Rosco', 'Juego de preguntas tipo rosco para poner a prueba tus conocimientos de programación.', 'Domingo Pérez', 'rosco', 'Programación', '9-12 años', 1);
INSERT INTO games (title, description, author, folder_name, category, age_group, approved) VALUES ('Snake Programer', 'En este juego, controlas una serpiente que, en lugar de comer simples manzanas o frutas, consume ´tokens de programación´ que van apareciendo en el tablero. Cada token representa un elemento de código (variables, funciones, operadores, etc.) que se va agregando a tu ´editor de código´ al ser consumido.', 'Sol Méndez', 'snake', 'Programación', '9-12 años', 1);
